type NotificationSettings = {
  email: boolean;
  push: boolean;
  sms: boolean;
}

const SettingsPage = () => {
  const [settings, setSettings] = useState<NotificationSettings>({
    email: true,
    push: false,
    sms: false,
  });

  const handleToggle = (name: keyof NotificationSettings) => {
    setSettings((prevSettings) => ({
      ...prevSettings,
      [name]: !prevSettings[name],
    }));
  };

  const ToggleSwitch: React.FC<{ label: string; name: keyof NotificationSettings; checked: boolean; onToggle: (name: keyof NotificationSettings) => void }> = ({
    label,
    name,
    checked,
    onToggle,
  }) => (
    <div className="flex items-center justify-between w-[330px] my-[12px]">
      <span className="text-[15px] font-[500] text-[#333]">{label}</span>
      <button
        type="button"
        className={`relative inline-flex flex-shrink-0 h-[24px] w-[44px] border-[2px] ${checked ? 'border-[#3B82F6]' : 'border-[#D1D5DB]'} rounded-full cursor-pointer transition-colors ease-in-out duration-200 focus:outline-none focus:ring-[2px] focus:ring-offset-[2px] focus:ring-[#3B82F6]`}
        role="switch"
        aria-checked={checked}
        onClick={() => onToggle(name)}
      >
        <span
          aria-hidden="true"
          className={`pointer-events-none inline-block h-[20px] w-[20px] rounded-full bg-white shadow-lg transform ring-0 transition ease-in-out duration-200 ${checked ? 'translate-x-[20px]' : 'translate-x-[0px]'}`}
        ></span>
      </button>
    </div>
  );

  return (
    <div className="flex flex-col items-center p-[24px] bg-[#F9FAFB] min-h-screen">
      <div className="bg-white rounded-[8px] shadow-sm p-[24px] w-[400px]">
        <h2 className="text-[20px] font-[600] text-[#1F2937] mb-[20px]">Notification Preferences</h2>

        <div className="flex flex-col gap-[10px]">
          <ToggleSwitch
            label="Email Notifications"
            name="email"
            checked={settings.email}
            onToggle={handleToggle}
          />
          <ToggleSwitch
            label="Push Notifications"
            name="push"
            checked={settings.push}
            onToggle={handleToggle}
          />
          <ToggleSwitch
            label="SMS Notifications"
            name="sms"
            checked={settings.sms}
            onToggle={handleToggle}
          />
        </div>
      </div>
    </div>
  );
};

export default SettingsPage;

