import React, { useState, useEffect, useCallback } from 'react';
import { debounce } from 'lodash';

type SearchBarProps = {
  placeholder?: string;
  initialValue?: string;
  onSearch: (searchTerm: string) => void;
  debounceTime?: number;
}

const SearchBar: React.FC<SearchBarProps> = ({
  placeholder = "Search...",
  initialValue = "",
  onSearch,
  debounceTime = 300,
}) => {
  const [searchTerm, setSearchTerm] = useState<string>(initialValue);

  // eslint-disable-next-line react-hooks/exhaustive-deps
  const debouncedOnSearch = useCallback(
    debounce((value: string) => {
      onSearch(value);
    }, debounceTime),
    [onSearch, debounceTime]
  );

  useEffect(() => {
    debouncedOnSearch(searchTerm);
    return () => {
      debouncedOnSearch.cancel();
    };
  }, [searchTerm, debouncedOnSearch]);

  const handleChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    setSearchTerm(event.target.value);
  };

  return (
    <div className="relative flex items-center w-[300px] h-[36px]">
      <input
        type="text"
        placeholder={placeholder}
        value={searchTerm}
        onChange={handleChange}
        className="w-full h-full border-[1px] border-[#D1D5DB] rounded-[6px] py-[8px] pl-[12px] pr-[38px] text-[15px] font-[400] text-[#333] focus:outline-none focus:border-[#0070F3] placeholder:text-[#9CA3AF]"
      />
      <svg
        className="absolute right-[12px] w-[18px] h-[18px] text-[#9CA3AF]"
        fill="none"
        strokeLinecap="round"
        strokeLinejoin="round"
        strokeWidth="2"
        viewBox="0 0 24 24"
        stroke="currentColor"
      >
        <path d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path>
      </svg>
    </div>
  );
};

export default SearchBar;

type PaginationProps = {
  currentPage: number;
  totalPages: number;
  onPageChange: (page: number) => void;
}

const Pagination = ({ currentPage, totalPages, onPageChange }: PaginationProps) => {
  const getPageNumbers = () => {
    const pageNumbers = [];
    const maxPagesToShow = 5; // Fixed number of page buttons to display

    if (totalPages <= maxPagesToShow) {
      for (let i = 1; i <= totalPages; i++) {
        pageNumbers.push(i);
      }
    } else {
      let startPage = Math.max(1, currentPage - Math.floor(maxPagesToShow / 2));
      let endPage = Math.min(totalPages, currentPage + Math.floor(maxPagesToShow / 2));

      if (endPage - startPage + 1 < maxPagesToShow) {
        if (startPage === 1) {
          endPage = Math.min(totalPages, startPage + maxPagesToShow - 1);
        } else {
          startPage = Math.max(1, endPage - maxPagesToShow + 1);
        }
      }

      for (let i = startPage; i <= endPage; i++) {
        pageNumbers.push(i);
      }
    }
    return pageNumbers;
  };

  const pageNumbers = getPageNumbers();

  return (
    <div className="flex items-center justify-center gap-[4px] font-[500] text-[13px]">
      <button
        onClick={() => onPageChange(currentPage - 1)}
        disabled={currentPage === 1}
        className="flex items-center justify-center h-[32px] w-[32px] border-[1px] border-[#D1D5DB] rounded-[4px] disabled:opacity-50 disabled:cursor-not-allowed"
      >
        <svg xmlns="http://www.w3.org/2000/svg" className="h-[16px] w-[16px] text-[#4B5563]" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
          <path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7" />
        </svg>
      </button>

      {pageNumbers.map((page) => (
        <button
          key={page}
          onClick={() => onPageChange(page)}
          className={`flex items-center justify-center h-[32px] w-[32px] border-[1px] rounded-[4px]
            ${currentPage === page
              ? "bg-[#1C64F2] border-[#1C64F2] text-white"
              : "bg-white border-[#D1D5DB] text-[#4B5563] hover:bg-[#F9FAFB]"
            }`}
        >
          {page}
        </button>
      ))}

      <button
        onClick={() => onPageChange(currentPage + 1)}
        disabled={currentPage === totalPages}
        className="flex items-center justify-center h-[32px] w-[32px] border-[1px] border-[#D1D5DB] rounded-[4px] disabled:opacity-50 disabled:cursor-not-allowed"
      >
        <svg xmlns="http://www.w3.org/2000/svg" className="h-[16px] w-[16px] text-[#4B5563]" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
          <path strokeLinecap="round" strokeLinejoin="round" d="M9 5l7 7-7 7" />
        </svg>
      </button>
    </div>
  );
};

export default Pagination

type ModalProps = {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  children: React.ReactNode;
}

const Modal = ({ isOpen, onClose, title, children }: ModalProps) => {
  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-[100]">
      <div
        className="bg-white rounded-[8px] shadow-lg w-[min(90%,_500px)] max-h-[90vh] flex flex-col"
        onClick={(e) => e.stopPropagation()} // Prevent closing when clicking inside the modal content
      >
        <div className="flex justify-between items-center p-[16px] border-b-[1px] border-b-[#e0e0e0]">
          <h2 className="text-[18px] font-[600] text-[#333]">{title}</h2>
          <button
            onClick={onClose}
            className="text-[24px] text-[#666] hover:text-[#333] leading-[1]"
          >
            &times;
          </button>
        </div>
        <div className="p-[16px] overflow-y-auto flex-grow text-[14px] text-[#555]">
          {children}
        </div>
      </div>
    </div>
  );
};

export default Modal

type CountryType = "USA" | "Canada" | "Mexico" | "Germany" | "France" | "Japan" | "Australia";

type CountrySelectProps = {
  selectedCountry: CountryType;
  onCountryChange: (country: CountryType) => void;
};

const CountrySelect: React.FC<CountrySelectProps> = ({ selectedCountry, onCountryChange }) => {
  const handleChange = (event: React.ChangeEvent<HTMLSelectElement>) => {
    onCountryChange(event.target.value as CountryType);
  };

  const countries: CountryType[] = ["USA", "Canada", "Mexico", "Germany", "France", "Japan", "Australia"];

  return (
    <div className="relative w-[200px]">
      <select
        className="block appearance-none w-full bg-white border-[1px] border-[#D1D5DB] text-[#374151] py-[8px] px-[12px] pr-[30px] rounded-[5px] leading-tight focus:outline-none focus:border-[#2563EB]"
        value={selectedCountry}
        onChange={handleChange}
      >
        {countries.map((country) => (
          <option key={country} value={country}>
            {country}
          </option>
        ))}
      </select>
      <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-[8px] text-[#6B7280]">
        <svg
          className="fill-current h-[20px] w-[20px]"
          xmlns="http://www.w3.org/2000/svg"
          viewBox="0 0 20 20"
        >
          <path d="M9.293 12.95l.707.707L15.657 8l-1.414-1.414L10 10.828 5.757 6.586 4.343 8z" />
        </svg>
      </div>
    </div>
  );
};

export default CountrySelect;
